diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..7f835fa364c3 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4527,6 +4527,22 @@ static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
   if (PredOut != Pred &&
       isKnownNonZero(A, Q.DL, /*Depth=*/0, Q.AC, Q.CxtI, Q.DT))
     return new ICmpInst(PredOut, Op0, Op1);
+  // For signed LT/GT, we can use the monotonic decreasing property of NOT:
+  // (X ^ B) < X  ->  ~(X ^ B) > ~X  ->  (X ^ B ^ -1) > (X ^ -1)
+  // If X is itself a xor with -1, i.e., X = A ^ -1, then ~X = A.
+  // This simplifies to (B ^ A) > A.
+  if (Pred == ICmpInst::ICMP_SLT || Pred == ICmpInst::ICMP_SGT) {
+    Value *InnerA;
+    // Check if X (i.e., Op1) is xor with -1.
+    if (match(Op1, m_c_Xor(m_Value(InnerA), m_AllOnes()))) {
+      // X = InnerA ^ -1, so ~X = InnerA.
+      // New predicate: if Pred == ICmpInst::ICMP_SLT -> ICmpInst::ICMP_SGT else ICmpInst::ICMP_SLT.
+      ICmpInst::Predicate NewPred = (Pred == ICmpInst::ICMP_SLT) ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_SLT;
+      // Compute B ^ InnerA (i.e., B ^ ~X). Note that B is 'A' from earlier match.
+      Value *NewXor = IC.Builder.CreateXor(A, InnerA);
+      return new ICmpInst(NewPred, NewXor, InnerA);
+    }
+  }

   return nullptr;
 }

